entries.content:
---

在正文中输出以下`状态栏`在开头处：

<event>{{当前事件}}</event>
<location>{{get_message_variable::stat_data.世界.当前地点}}</location>
<day>{{get_message_variable::stat_data.世界.当前日期}}</day>
<time>{{get_message_variable::stat_data.世界.当前时辰}}</time>
<level>user境界: {{get_message_variable::stat_data.user.境界}}</level>
<xinfa> {{user}}心法：{{get_message_variable::stat_data.user.已修心法}}
表：{{user心法表象的效果}}
里：{{user心法里象的效果}}</xinfa>
<neigong>{{user}}内功：{{get_message_variable::stat_data.user.已修内功}} 
表：{{user内功表象的效果}}
里：{{user内功里象的效果}}
</neigong>

当出现女角色时，在正文中输出以下`状态栏`在正文的结尾处：

<name>{{get_message_variable::stat_data.character_name}}</name>
<char_level>Cảnh giới: {{get_message_variable::stat_data.character_name.cảnh_giới}}</char_level>

<char_inner>
Tâm pháp: {{get_message_variable::stat_data.character_name.đã_tu_tâm_pháp}}
Biểu tượng bên ngoài: {{get_message_variable::stat_data.character_name.tam_phap_bieu_tuong_ngoai}}
Biểu tượng bên trong: {{get_message_variable::stat_data.character_name.tam_phap_bieu_tuong_trong}}
</char_inner>

<char_power>
Nội công: {{get_message_variable::stat_data.character_name.đã_tu_nội_công}}
Biểu tượng bên ngoài: {{get_message_variable::stat_data.character_name.noi_cong_bieu_tuong_ngoai}}
Biểu tượng bên trong: {{get_message_variable::stat_data.character_name.noi_cong_bieu_tuong_trong}}
</char_power>

<intimacy>Độ thân mật: {{get_message_variable::stat_data.character_name.độ_thân_mật}}</intimacy>

<top>Áo: {{get_message_variable::stat_data.character_name.áo}}</top>
<bottom>Quần: {{get_message_variable::stat_data.character_name.quần}}</bottom>
<underwear>Nội y: {{get_message_variable::stat_data.character_name.nội_y}}</underwear>
<accessories>Phụ kiện: {{get_message_variable::stat_data.character_name.phụ_kiện}}</accessories>

<char_pic>{{get_message_variable::stat_data.character_name.hình_vẽ}}</char_pic>

---
<status_current_variables>
user:
  性别: {{get_message_variable::stat_data.user.性别}}
  境界: {{get_message_variable::stat_data.user.境界}}
  已修心法: {{get_message_variable::stat_data.user.已修心法}}
  已修内功: {{get_message_variable::stat_data.user.已修内功}} 
  已修外功: {{get_message_variable::stat_data.user.已修外功}}
  内力值: {{get_message_variable::stat_data.user.内力值}} # 当前内力值/内力值上限
  血气值: {{get_message_variable::stat_data.user.血气值}} # 当前血气值/血气值上限
  功法增幅: {{get_message_variable::stat_data.user.功法增幅}}
世界:
  当前地点: {{get_message_variable::stat_data.世界.当前地点}} # 格式为：地区-具体地点
  当前日期: {{get_message_variable::stat_data.世界.当前日期}}
  当前时辰: {{get_message_variable::stat_data.世界.当前时辰}}
  NSFW判断: {{get_message_variable::stat_data.世界.NSFW判断}}
[character_name]:
  境界: {{get_message_variable::stat_data.character_name.境界}}
  特殊体质: {{get_message_variable::stat_data.character_name.特殊体质}}
  已修心法: {{get_message_variable::stat_data.character_name.已修心法}}
  已修内功: {{get_message_variable::stat_data.character_name.已修内功}}
  已修外功: {{get_message_variable::stat_data.character_name.已修外功}}
  内力值: {{get_message_variable::stat_data.character_name.内力值}}
  血气值: {{get_message_variable::stat_data.character_name.血气值}}
  功法增幅: {{get_message_variable::stat_data.character_name.功法增幅}}
  亲密度: {{get_message_variable::stat_data.character_name.亲密度}} # 与<user>的亲密程度
  上衣: {{get_message_variable::stat_data.character_name.上衣}} # 主要穿着的服装上衣或套装
  下装: {{get_message_variable::stat_data.character_name.下装}} # 裤子或裙子
  内衣: {{get_message_variable::stat_data.character_name.内衣}} # 内衣搭配
  配饰: {{get_message_variable::stat_data.character_name.配饰}} # 配饰（包含道具，玩具）

</status_current_variables> （无需输出在正文）

format: |-
  <update>
  <update_analysis>$(根据剧情进展更新人物与世界状态)
  ${
  - calculate time passed: 根据世界.当前日期和世界.当前时辰的变化计算时间流逝。
  - analyze every variable based on its corresponding `check`:
    - 初始化<user>性别。
    - 设定或更新<user>/角色已修心法/内功/外功。
    - 根据人物境界设定并调整内力值/血气值/功法增幅
    - 设定并更新character_name的服装变化(包含服饰本身状态变化和更换服饰)。
    - 检查character_name的亲密度变化，根据互动内容增减。且当character_name离场时，亲密度固定。
    - 检查地点、日期、时辰是否发生变化，并更新。
    - 检查NSFW剧情是否发生将要发生，并更新。
  }
  </update_analysis>
  _.set('character_name.亲密度', ${old_value}, ${new_value}); // 理由：与character_name进行了亲密互动。
  _.set('user.内力值', ${old_value}, ${new_value}); // 理由：修炼了《天根宝典》。
  _.set('世界.当前时辰', '酉时'); // 理由：剧情时间推进。
  </update>
